use std::process::Command;

fn convert_file(filename: &str, format: &str) -> String {
    let mut cmd = Command::new("convert");
    cmd.arg(filename);
    cmd.arg("-f").arg(format);
    let output = cmd.output().unwrap();
    String::from_utf8(output.stdout).unwrap()
}